        XCTAssertEqual(Complex(2, -1.4), z - x)
    }


    func testMultiplication() {

        let z = Complex(1, 2)
        let x = Complex(-1, 3.4)

        XCTAssertEqual(Complex(-7.8, 1.4), z * x)
        XCTAssertEqual(Complex(-7.8, 1.4), x * z)
